INSERT INTO stock_market (
    stock_code, market, exchange_code, provider_market_code, stock_name, status
) VALUES (
    #{stockCode}, #{market}, #{exchangeCode}, #{providerMarketCode}, #{stockName}, #{status}
)
ON DUPLICATE KEY UPDATE
    id = LAST_INSERT_ID(id),
    stock_name = COALESCE(stock_name, VALUES(stock_name)),
    exchange_code = COALESCE(exchange_code, VALUES(exchange_code)),
    provider_market_code = COALESCE(provider_market_code, VALUES(provider_market_code))
